#include <bits/stdc++.h>
using namespace std;
struct Stu{
    int k,s;
}st[5003];
bool cmp(Stu x,Stu y){
    if(x.s==y.s)
        return x.k<y.k;
    return x.s>y.s;
}
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        cin>>st[i].k>>st[i].s;
    sort(st+1,st+n+1,cmp);
    int p=st[int(m*1.5)].s,sum=n+1;
    for(int i=1;i<=n;i++)
        if(st[i].s<p){
            sum=i;
            break;
        }
    cout<<p<<' '<<sum-1<<endl;
    for(int i=1;i<sum;i++)
        cout<<st[i].k<<' '<<st[i].s<<endl;
    return 0;
}
